import{_ as i,C as o,o as n,c as s,ai as a,E as d,w as r,a as l}from"./chunks/framework.BH_J6TYN.js";const C=JSON.parse('{"title":"Mini Order (SC-XXXX)","description":"Código de seguimiento que identifica cada pedido de tu tienda digital","frontmatter":{"title":"Mini Order (SC-XXXX)","description":"Código de seguimiento que identifica cada pedido de tu tienda digital"},"headers":[],"relativePath":"cat/mini-order-sc.md","filePath":"cat/mini-order-sc.md"}'),c={name:"cat/mini-order-sc.md"};function p(u,e,h,m,g,b){const t=o("Note");return n(),s("div",null,[e[1]||(e[1]=a('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>El <strong>Mini Order</strong> es el sistema de códigos de seguimiento de SYNTIcat. Cada pedido que un cliente envía desde el carrito recibe automáticamente un código único en formato <strong>SC-XXXX</strong> (ejemplo: SC-0001, SC-0042, SC-0123). Este código viaja en el mensaje de WhatsApp y queda guardado como archivo JSON en tu espacio del servidor.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><strong>En la landing (lo que ve tu cliente):</strong></p><ul><li>El código SC-XXXX aparece en el mensaje de WhatsApp al finalizar el pedido</li><li>También aparece en la pantalla de confirmación después de enviar el pedido</li></ul><p><strong>En el servidor:</strong></p><ul><li>Los pedidos se guardan en <code>storage/tenants/{tu_tenant_id}/orders/2026/03/SC-XXXX.json</code></li><li>Organizados por año y mes automáticamente</li></ul><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><ul><li><strong>Genera un código secuencial único</strong> para cada pedido (SC-0001, SC-0002, SC-0003...)</li><li><strong>Guarda el pedido completo como JSON</strong>: productos, cantidades, variantes, precios, total y fecha</li><li><strong>Incluye el código en el mensaje de WhatsApp</strong> para que ambos (tú y el cliente) tengan la misma referencia</li><li><strong>Pantalla de confirmación</strong>: El cliente ve el código SC-XXXX después de enviar su pedido</li></ul><h3 id="para-que-sirve-el-codigo" tabindex="-1">Para qué sirve el código <a class="header-anchor" href="#para-que-sirve-el-codigo" aria-label="Permalink to &quot;Para qué sirve el código&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Uso</th><th>Ejemplo</th></tr></thead><tbody><tr><td><strong>Identificar pedidos</strong></td><td>&quot;¿Tu pedido es el SC-0047? Déjame revisarlo&quot;</td></tr><tr><td><strong>Evitar confusiones</strong></td><td>Si tienes 3 pedidos similares, el código los distingue</td></tr><tr><td><strong>Profesionalismo</strong></td><td>Le da imagen de negocio organizado</td></tr><tr><td><strong>Seguimiento</strong></td><td>&quot;Tu pedido SC-0047 ya está listo para recoger&quot;</td></tr></tbody></table><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li><strong>No rastrea estados</strong> (preparando, enviado, entregado) — eso se coordina por WhatsApp</li><li><strong>No envía notificaciones</strong> automáticas al cliente sobre su pedido</li><li><strong>No tiene panel de órdenes</strong> visible en el panel (próximamente)</li><li><strong>No genera factura</strong> a partir del pedido</li><li><strong>No permite cancelar</strong> un pedido desde la plataforma</li><li><strong>No tiene historial de pedidos</strong> visible para el cliente</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Básico</th><th>Semestral</th><th>Anual</th></tr></thead><tbody><tr><td>Código SC-XXXX</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>JSON guardado en servidor</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>Pantalla de confirmación</td><td>❌</td><td>❌</td><td>✅</td></tr></tbody></table>',15)),d(t,null,{default:r(()=>[...e[0]||(e[0]=[l(" El Mini Order con código SC-XXXX es exclusivo del plan **Anual** (REF 69/año). En el plan Semestral hay carrito pero sin código de seguimiento. ",-1)])]),_:1}),e[2]||(e[2]=a(`<h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-tienda-de-zapatos-pasofirme-en-san-cristobal" tabindex="-1">Caso: Tienda de zapatos &quot;PasoFirme&quot; en San Cristóbal <a class="header-anchor" href="#caso-tienda-de-zapatos-pasofirme-en-san-cristobal" aria-label="Permalink to &quot;Caso: Tienda de zapatos &quot;PasoFirme&quot; en San Cristóbal&quot;">​</a></h3><p>Andrea tiene una tienda de zapatos con plan Anual. Un cliente pide:</p><ul><li>1× Bota montañera (Talla 42) — REF 35</li><li>1× Par de medias — REF 5</li></ul><p>Al tocar &quot;Finalizar pedido&quot;, se genera el código <strong>SC-0023</strong>. El mensaje que recibe Andrea por WhatsApp:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🛍️ Nuevo pedido SYNTIcat</span></span>
<span class="line"><span>📦 Orden: SC-0023</span></span>
<span class="line"><span></span></span>
<span class="line"><span>• 1× Bota montañera (Talla 42) — REF 35.00</span></span>
<span class="line"><span>• 1× Par de medias — REF 5.00</span></span>
<span class="line"><span></span></span>
<span class="line"><span>💰 Total: REF 40.00</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Código de seguimiento: SC-0023</span></span></code></pre></div><p>Andrea confirma: <em>&quot;Hola, tu pedido SC-0023 está listo. ¿Lo recoges o te lo envío? Pago Móvil Banesco al 04141234567&quot;</em></p><p>El archivo <code>SC-0023.json</code> queda guardado en el servidor para referencia futura.</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/cat/carrito-whatsapp.html">Carrito y WhatsApp</a> — Cómo funciona el checkout</li><li><a href="/cat/que-es-synticat.html">¿Qué es SYNTIcat?</a> — Planes y comparativa</li><li><a href="/shared/whatsapp.html">WhatsApp</a> — Canal de comunicación con clientes</li></ul>`,10))])}const f=i(c,[["render",p]]);export{C as __pageData,f as default};
